import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (name, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    proj, tfm, pkg = k
    if bv != av:
        status = 'Aligned to highest' if bv and av else ('Added' if not bv else 'Removed')
        changes.append((proj, tfm, pkg, bv or '-', av or '-', status))
    else:
        unchanged.append((proj, tfm, pkg, av))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'{c[0]:15} {c[1]:8} {c[2]:50} {c[3]:10} -> {c[4]:10}  [{c[5]}]')
else:
    print('None')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]:15} {u[1]:8} {u[2]:50} {u[3]}')
"
